    SELECT
        {{grid_columns_sql}}
    FROM {{main_table}} a
    /* OPTIONAL: LEFT OUTER JOIN {{lookup_table}} b ON a.comp_cd = b.comp_cd AND a.xxx = b.xxx */
    WHERE a.comp_cd = #{login_comp_cd}

        AND a.brndz_cd = #{P_brndz_cd}

    {{search_conditions_sql}}
